import Image from 'next/image'
import { Button } from '@/components/ui/button'

export default function AboutPage() {
  return (
    <main className="min-h-screen bg-[#FDFCF0]">
      {/* 1. Hero Page Header */}
      <section className="relative h-[60vh] flex items-center justify-center overflow-hidden bg-[#3E2723]">
        <Image 
          src="/images/about-hero.jpg" // Hãy thay bằng ảnh không gian quán hoặc đồi chè
          alt="Trung Nguyen Legend Story"
          fill
          className="object-cover opacity-40"
        />
        <div className="relative z-10 text-center space-y-4">
          <h1 className="text-5xl md:text-7xl font-bold text-[#C5A059] uppercase tracking-[0.2em]">
            Our Story
          </h1>
          <p className="text-white/80 tracking-widest uppercase text-sm">
            The Journey of Awakening and Creativity
          </p>
        </div>
      </section>

      {/* 2. The Philosophy Section */}
      <section className="py-20 container mx-auto px-4">
        <div className="grid md:grid-cols-2 gap-16 items-center">
          <div className="space-y-6">
            <h2 className="text-3xl md:text-5xl font-bold text-[#3E2723] leading-tight">
              MORE THAN JUST A CUP OF <br />
              <span className="text-[#C5A059]">ENERGY COFFEE</span>
            </h2>
            <p className="text-[#5D4037] text-lg leading-relaxed">
              Founded in 1996 in Buon Ma Thuot - the coffee capital of Vietnam, Trung Nguyen Legend has 
              relentlessly pursued the mission of honoring Vietnamese coffee on the world map.
            </p>
            <p className="text-[#5D4037] text-lg leading-relaxed italic border-l-4 border-[#C5A059] pl-6">
              "Coffee is the source of energy for great souls on the path to conquering success and creating the future."
            </p>
          </div>
          <div className="relative h-[400px]">
            <Image 
              src="/images/philosophy.jpg" 
              alt="Coffee Philosophy"
              fill
              className="object-cover rounded-none"
            />
          </div>
        </div>
      </section>

      {/* 3. Three Coffee Civilizations (Nét đặc trưng nhất của Trung Nguyên) */}
      <section className="py-20 bg-[#1a1a1a] text-white">
        <div className="container mx-auto px-4 text-center mb-16">
          <h2 className="text-[#C5A059] text-3xl font-bold uppercase tracking-widest mb-4">
            3 Coffee Civilizations
          </h2>
          <div className="w-24 h-1 bg-[#C5A059] mx-auto"></div>
        </div>
        
        <div className="container mx-auto px-4 grid md:grid-cols-3 gap-12">
          {[
            { title: 'Ottoman', desc: 'The civilization that considers coffee as a spiritual drink.' },
            { title: 'Roman', desc: 'Representing the power of organization and application.' },
            { title: 'Thien (Zen)', desc: 'A coffee civilization created by Trung Nguyen Legend.' },
          ].map((item, index) => (
            <div key={index} className="text-center space-y-4 border border-zinc-800 p-8 hover:border-[#C5A059] transition-colors">
              <h3 className="text-[#C5A059] text-2xl font-bold uppercase tracking-wide">{item.title}</h3>
              <p className="text-zinc-400 leading-relaxed">{item.desc}</p>
            </div>
          ))}
        </div>
      </section>

      {/* 4. Call to Action */}
      <section className="py-20 text-center">
        <h2 className="text-3xl font-bold text-[#3E2723] mb-8 uppercase tracking-widest">
          Join Our Community
        </h2>
        <Button className="bg-[#3E2723] hover:bg-[#2A1B18] text-white rounded-none px-12 py-8 text-xs font-bold tracking-[0.2em] uppercase">
          Explore Our Products
        </Button>
      </section>
    </main>
  )
}